mapper.select:
SELECT id.hq_code as hqCode, ih.hq_name as hqName, id.wp_code as wpCode, iw.wp_name as wpName, id.dm_code as dmCode, id.dm_name as dmName, id.user_company_code as userCompanyCode, id.reg_ymd as regYmd, id.status as status FROM IV_DEPARTMENT id LEFT JOIN IV_WORKPLACE iw ON id.hq_code = iw.hq_code AND id.wp_code = iw.wp_code AND (id.user_company_code = iw.user_company_code OR (id.user_company_code IS NULL AND iw.user_company_code IS NULL)) LEFT JOIN IV_HEADQUARTERS ih ON iw.hq_code = ih.hq_code AND (id.user_company_code = ih.user_company_code OR (id.user_company_code IS NULL AND ih.user_company_code IS NULL)) WHERE 1 = 1
AND id.user_company_code = #{userCompanyCode}
AND id.hq_code = #{hqCode}
AND id.wp_code = #{wpCode}
AND id.dm_code = #{dmCode}
AND id.dm_name LIKE CONCAT('%', #{dmName}, '%')

SELECT hq_code as hqCode, wp_code as wpCode, dm_code as dmCode, dm_name as dmName, user_company_code as userCompanyCode, reg_ymd as regYmd, status as status FROM IV_DEPARTMENT WHERE 1 = 1 AND wp_code = #{wpCode} AND hq_code = #{hqCode} AND dm_code = #{dmCode}
and user_company_code = #{userCompanyCode}
and user_company_code IS NULL

